settings.custom_liquid:
{% if product.available %}
<div style="text-align: center;">
  <div class="instock-pulse">
    <span class="icon--pulsing"></span>
    <span id="low-stock-message" style="color: #000;">Low stock (loading...)</span>
  </div>

  <script>
    document.addEventListener('DOMContentLoaded', function() {
      var lowStockMessage = document.getElementById('low-stock-message');

      function getRandomNumber() {
        return Math.floor(Math.random() * 11) + 10; // Generates a random number between 10 and 20
      }

      function updateLowStockMessage() {
        var storedTimestamp = localStorage.getItem('lowStockTimestamp');
        var currentTime = new Date().getTime();
        var timeDifference = currentTime - storedTimestamp;

        var storedRandomNumber = parseInt(localStorage.getItem('lowStockRandomNumber'));

        if (!storedTimestamp || timeDifference > 30 * 60 * 1000 || isNaN(storedRandomNumber)) {
          storedRandomNumber = getRandomNumber();
          localStorage.setItem('lowStockRandomNumber', storedRandomNumber);
          localStorage.setItem('lowStockTimestamp', currentTime);
        } else if (storedRandomNumber === 2) {
          storedRandomNumber = getRandomNumber();
          localStorage.setItem('lowStockRandomNumber', storedRandomNumber);
        } else if (storedRandomNumber > 2) {
          storedRandomNumber -= 1;
          localStorage.setItem('lowStockRandomNumber', storedRandomNumber);
        }

        // Check if the URL contains "/de" for German or "/fr-fr" for French
        var urlContainsDE = window.location.href.indexOf('/de') !== -1;
        var urlContainsFR = window.location.href.indexOf('/fr-fr') !== -1;

        if (urlContainsDE) {
          lowStockMessage.textContent = 'Niedriger Lagerbestand (' + storedRandomNumber + ' Stücke übrig)';
        } else if (urlContainsFR) {
          lowStockMessage.textContent = 'Stock faible (' + storedRandomNumber + ' pièces restantes)';
        } else {
          lowStockMessage.textContent = 'Low stock (' + storedRandomNumber + ' pieces left)';
        }
      }

      updateLowStockMessage();

      setInterval(updateLowStockMessage, 30 * 60 * 1000); // Update every 30 minutes
    });
  </script>

  <style>
    .instock-pulse {
      display: flex;
      flex-wrap: nowrap;
      align-items: center;
      justify-content: center;
    }

    .icon--pulsing {
      position: relative;
      width: 20px;
      height: 20px;
      margin-right: 10px;
    }

    .icon--pulsing:after,
    .icon--pulsing:before {
      background: #F4AF29;
      width: 10px;
      height: 10px;
      border-radius: 10px;
      position: absolute;
      left: 0;
      top: 0;
      content: "";
      margin: 5px;
    }

    @keyframes inventory-pulse {
      0% {
        opacity: 0.5;
      }
      to {
        transform: scale(2.5);
        opacity: 0;
      }
    }

    .icon--pulsing:before {
      animation: inventory-pulse 2s linear infinite;
    }

    /* Media Query for Font Size on Mobile */
    @media (max-width: 768px) {
      #low-stock-message {
        font-size: 17px;
      }
    }
  </style>

</div>
{% endif %}
